INSERT INTO "campaigns" ("slug", "category", "title", "summary", "description", "image", "origin", "unit_price", "service_fee", "moq", "committed", "deadline", "status") VALUES
('stray-kids-dominate-albums', 'kpop', 'Stray Kids ''Dominate'' Album (Ktown4u Ver.)', 'Batch pre-order + POB photocard set, ongkir dibagi rata untuk seluruh member komunitas.', 'Album resmi Stray Kids diambil langsung dari toko album resmi Korea, lengkap dengan pre-order benefit (photocard set + poster) selama masih tersedia dari distributor. Kami gabungkan pesanan dari seluruh peserta jastip menjadi satu kiriman kolektif agar ongkos kirim internasional bisa ditekan jauh lebih murah dibanding order sendiri-sendiri. Setiap peserta cukup transfer sesuai jumlah album yang diinginkan, sisanya kami yang urus mulai dari pemesanan, penerimaan di gudang, sampai pengemasan ulang untuk pengiriman domestik.', '/placeholder.png', 'Ktown4u (Korea)', 285000, 25000, 20, 14, '2026-08-15 23:59:00', 'open'),
('newjeans-lightstick-v2', 'kpop', 'NewJeans Official Lightstick Ver.2', 'Lightstick resmi dari Weverse Shop, batch gabungan untuk menekan bea masuk & ongkir.', 'Lightstick resmi NewJeans versi kedua, dipesan langsung dari Weverse Shop. Karena barang ini cukup besar dan berat, sistem group order sangat membantu menekan biaya kirim udara per unit. Kami menunggu hingga kuota minimum tercapai sebelum melakukan pemesanan massal ke distributor, sehingga harga yang didapat komunitas jauh lebih kompetitif dibanding membeli satuan.', '/placeholder.png', 'Weverse Shop (Korea)', 650000, 35000, 15, 9, '2026-08-01 23:59:00', 'open'),
('seventeen-fan-con-md', 'kpop', 'SEVENTEEN Fan-Con Official Merchandise Bundle', 'Bundle merch fan-con (slogan, keychain, mini photobook) via platform fan-merch resmi.', 'Bundle merchandise eksklusif dari rangkaian fan concert SEVENTEEN, hanya dijual selama periode terbatas melalui platform resmi. Kami menjadi fasilitator pembelian kolektif agar penggemar di Indonesia tetap bisa mendapatkan item ini tanpa harus punya kartu kredit internasional atau alamat pengiriman luar negeri sendiri.', '/placeholder.png', 'Official Fan-Merch Platform (Korea)', 410000, 30000, 25, 25, '2026-07-20 23:59:00', 'locked'),
('magsafe-power-bank-tren', 'gadget', 'MagSafe Power Bank 10000mAh Wireless', 'Power bank magnetik yang lagi tren di TikTok, batch impor kolektif langsung dari supplier.', 'Power bank magnetik dengan wireless charging yang belakangan viral di media sosial. Kami mendatangkan unit ini secara kolektif dari supplier tepercaya untuk mendapatkan harga grosir, lalu membagikannya ke pembeli lokal dengan margin yang wajar. Setiap batch memiliki kuota minimum agar ongkos kirim dan bea bisa ditekan serendah mungkin.', '/placeholder.png', 'Supplier Aksesoris Gadget (Guangzhou)', 235000, 20000, 30, 22, '2026-07-25 23:59:00', 'open'),
('retro-mechanical-keycaps', 'gadget', 'Set Keycap Mechanical Retro Cream', 'Keycap set custom yang sedang tren di kalangan pecinta keyboard mechanical.', 'Set keycap bertema retro cream yang populer di komunitas mechanical keyboard. Karena diproduksi terbatas oleh pengrajin independen, kami mengumpulkan pesanan dari komunitas terlebih dahulu sebelum melakukan pemesanan batch ke produsen, memastikan tidak ada kelebihan stok dan setiap pembeli mendapat harga terbaik.', '/placeholder.png', 'Independent Keycap Maker (Taiwan)', 320000, 25000, 20, 6, '2026-08-10 23:59:00', 'open');
